const body = $input.first().json.body || $input.first().json;
const message   = body.message   || '';
const sessionId = body.sessionId || 'default';
if (!message.trim()) throw new Error('Empty message');
return [{ json: { message, sessionId } }];

// Build context from Qdrant search results and prepare the prompt
const message   = $('Parse Input').first().json.message;
const searchResult = $input.first().json;

console.log('--- RAG DEBUG ---');
console.log('Query:', message);
console.log('Raw Search Hits:', (searchResult.result || []).length);

// Relaxed filtering: accept anything with payload text
const hits = (searchResult.result || []).filter(h => h.payload && h.payload.text);
console.log('Filtered Hits:', hits.length);
if (hits.length > 0) {
    console.log('Top Hit:', hits[0].payload.filename, hits[0].score);
    console.log('Top Hit Text Snippet:', hits[0].payload.text.slice(0, 100));
}

let context = '';
const sources = [];

if (hits.length > 0) {
  context = hits.map((h, i) => {
    const fn  = h.payload.filename || 'unknown';
    const txt = h.payload.text     || '';
    const score = h.score || 0;
    sources.push({ file: fn, excerpt: txt.slice(0, 200), score: Math.round(score * 100) });
    return `[Source ${i+1}: ${fn} (Score: ${score.toFixed(2)})]\n${txt}`;
  }).join('\n\n---\n\n');
}

const systemPrompt = context
  ? `You are a knowledgeable assistant for Riga City Council, helping citizens and staff understand municipal documents, budgets, regulations, and policies.\n\n## Instructions\n- Answer based ONLY on the provided document context below — do not invent or assume facts not present in the context\n- If the context is insufficient to fully answer the question, clearly state what information is missing or unavailable\n- Structure your answers with clear markdown formatting:\n  - Use **bold** for key terms, names, amounts, and dates\n  - Use bullet points or numbered lists for multiple items or steps\n  - Use headings (##) only for multi-section answers\n- When quoting specific figures, dates, or legal references from the documents, cite them accurately\n- Reference your sources naturally (e.g. "According to [filename]..." or "As stated in [filename]...")\n- Respond in the same language as the user's question: in Latvian (latviski) if asked in Latvian, in English if asked in English\n- Be precise and concise — avoid unnecessary filler phrases like "Great question!" or "Certainly!"\n- If the question is ambiguous, answer the most likely interpretation and note any assumptions\n\n## Document Context\n${context}`
  : `You are a knowledgeable assistant for Riga City Council. No relevant documents were found in the index for this query (Search returned 0 results).\n\nINSTRUCTIONS:\n1. Inform the user that you couldn't find specific documents related to their query in the local knowledge base.\n2. You may provide a general answer based on your broad training data, but clearly state that it's NOT from the official documents.\n3. Suggest they rephrase or check the official Riga.lv website if applicable.\n\nUser Question: ${message}`;

console.log('Generated Prompt Length:', systemPrompt.length);
return [{ json: { message, systemPrompt, sources } }];

const ollamaResp = $input.first().json;
const answer  = ollamaResp.message?.content || 'Sorry, I could not generate a response.';
const sources = $('Build RAG Prompt').first().json.sources || [];
return [{ json: { answer, sources, executionId: $execution.id } }];
